// B) :540 spawnBoss 加入场仪式 (~1.8s)
spawnBoss(type){
  this.cameras.main.shake(1500,0.012);
  this.tweens.add({targets:this.vignetteRect, alpha:0.5, duration:800});
  this.seaSplash.explode(80, DW/2, HORIZON_Y);
  AudioFX.bossEntrance(type); // 低频 sub-drop + whoosh
  bgmCrossfade(this.bgmBattle, this.bgmBoss, 400);
  this.showBanner(TYPES[type].bossName, '#ff2222', 1500);
  // BOSS 从远处(z.t=0.1) tween 到 spawn 位置,2s
  const boss = this.createBoss(type, {tStart:0.1});
  this.tweens.add({targets:boss, t:0.6, duration:2000});
}

// C) update 监听 phase shift(在 zombie 更新循环里)
if(z.cfg.boss && !z.phase2 && z.hp <= z.maxHP*0.66){
  z.phase2 = true;
  z.cfg.speed *= 1.4;
  for(let i=0;i<2;i++) this.spawnAdd('runner', z.x);
  AudioFX.bossPhase();
  this.cameras.main.shake(600, 0.008);
}
if(z.cfg.boss && !z.phase3 && z.hp <= z.maxHP*0.33){
  z.phase3 = true;
  z.cfg.speed *= 1.2;
  for(let i=0;i<3;i++) this.spawnAdd('runner', z.x);
  AudioFX.bossPhase();
  this.chromaticAberration(300);
}

// D) :765 BOSS death — 全屏白闪 + 冲击波环 + timeScale 0.5 持续 600ms + chromatic
if(z.cfg.boss){
  this.flash.setAlpha(0.9);
  this.time.timeScale = 0.5;
  this.time.delayedCall(600,()=>this.time.timeScale=1);
  const shock = this.add.circle(z.x, z.y, 20).setStrokeStyle(6,0xffffff).setDepth(80);
  this.tweens.add({targets:shock, radius:600, alpha:0, duration:800, onComplete:()=>shock.destroy()});
  AudioFX.bossDeath(z.cfg.boss); // 二选一专属
}

