// 在 AudioFX IIFE 内加:
const masterGain = a.createGain();
const masterLP = a.createBiquadFilter();
masterLP.type='lowpass'; masterLP.frequency.value=18000;
masterLP.connect(masterGain).connect(a.destination);
// 所有 burst/tone/noise 改 connect(masterLP) 替代 a.destination
return {
  ...existing,
  diveIn(){
    masterLP.frequency.linearRampToValueAtTime(600, a.currentTime+0.25);
    if(window.game?.bgmBattle) window.game.bgmBattle.volume = 0.18;
    /* play whoosh */
  },
  diveOut(){
    masterLP.frequency.linearRampToValueAtTime(18000, a.currentTime+0.4);
    if(window.game?.bgmBattle) window.game.bgmBattle.volume = 0.55;
  },
  bossEntrance(t){ /* 60Hz sub + 600ms whoosh */ },
  bossPhase(){ /* sub-drop 80→30Hz over 400ms */ },
  bossDeath(t){ /* t==='tidelord'? 金属冰冷长尾 : 肉感低吼塌缩 */ }
};

